CREATE TABLE UserRole (Id INT IDENTITY PRIMARY KEY, Name VARCHAR(50) NOT NULL UNIQUE);
CREATE TABLE AppUser (Id INT IDENTITY PRIMARY KEY, Email VARCHAR(255) NOT NULL UNIQUE, PasswordHash VARCHAR(500) NOT NULL, FullName VARCHAR(200) NOT NULL, RoleId INT NOT NULL, IsActive BIT NOT NULL DEFAULT 1, CreatedByUserId INT NULL, CreatedAt DATETIME2 NOT NULL DEFAULT SYSUTCDATETIME(), FOREIGN KEY(RoleId) REFERENCES UserRole(Id));
CREATE TABLE Student (Id INT IDENTITY PRIMARY KEY, AppUserId INT NOT NULL, FullName VARCHAR(200) NOT NULL, SaIdNumber VARCHAR(13) NULL, PassportNumber VARCHAR(50) NULL, IsForeignStudent BIT NOT NULL DEFAULT 0, FinalAps INT NULL, FOREIGN KEY(AppUserId) REFERENCES AppUser(Id));
CREATE TABLE ForeignStudentProfile (Id INT IDENTITY PRIMARY KEY, StudentId INT NOT NULL, CountryOfCitizenship VARCHAR(100), CountryOfResidence VARCHAR(100), VisaStatus VARCHAR(100), StudyPermitStatus VARCHAR(100), MedicalCoverStatus VARCHAR(100), QualificationCountry VARCHAR(100), QualificationType VARCHAR(150), SaqaStatus VARCHAR(100), UsafExemptionStatus VARCHAR(100), EnglishProficiencyStatus VARCHAR(100), TranslationRequired BIT NOT NULL DEFAULT 0, FOREIGN KEY(StudentId) REFERENCES Student(Id));
CREATE TABLE University (Id INT IDENTITY PRIMARY KEY, Name VARCHAR(200) NOT NULL, Province VARCHAR(100) NOT NULL, WebsiteUrl VARCHAR(300));
CREATE TABLE Course (Id INT IDENTITY PRIMARY KEY, UniversityId INT NOT NULL, Name VARCHAR(200) NOT NULL, Faculty VARCHAR(150), MinimumAps INT NOT NULL, Duration VARCHAR(50), ApplicationFee DECIMAL(10,2), ClosingDate DATE, FOREIGN KEY(UniversityId) REFERENCES University(Id));
CREATE TABLE Application (Id INT IDENTITY PRIMARY KEY, StudentId INT NOT NULL, CourseId INT NOT NULL, Status VARCHAR(50) NOT NULL DEFAULT 'Draft', PaymentStatus VARCHAR(50) NOT NULL DEFAULT 'Pending', SubmittedAt DATETIME2 NOT NULL DEFAULT SYSUTCDATETIME(), UpdatedAt DATETIME2 NOT NULL DEFAULT SYSUTCDATETIME(), FOREIGN KEY(StudentId) REFERENCES Student(Id), FOREIGN KEY(CourseId) REFERENCES Course(Id));
INSERT INTO UserRole(Name) VALUES ('SuperAdmin'),('Admin'),('UniversityStaff'),('SupportStaff'),('Student');
